when_add_category.content:
document.getElementById('addCategoryBtn').addEventListener('click', () => {
    const name = prompt('Enter category name:');
    const limit = parseFloat(prompt('Enter category limit:'));
    if (name && !isNaN(limit)) {
        budgetCategories.push({ name, balance: 0, limit });
        renderDashboard();
    }
});

