when_update_category_balance.content:
function editCategory(name) {
    const category = budgetCategories.find(c => c.name === name);
    const newBalance = parseFloat(prompt('Enter new balance:'));
    if (!isNaN(newBalance)) {
        category.balance = newBalance;
        renderDashboard();
    }
}

